```class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        int[] result = new int[n];
        int[] color = new int[n];
        Arrays.fill(color, -1);

        for (int[] edge : redEdges) {
            int a = edge[0], b = edge[1];
            color[a] = 1;
            color[b] = 1;
        }

        for (int[] edge : blueEdges) {
            int u = edge[0], v = edge[1];
            if (color[u] == -1) {
                color[u] = 1;
                color[v] = 1;
            } else if (color[u] == color[v]) {
                color[u] = -1;
            } else {
                color[u] = color[v] = -1;
            }
        }

        for (int i = 0; i < n; i++) {
            if (color[i] == -1) {
                for (int j = i + 1; j < n; j++) {
                    if (color[i] == color[j]) {
                        color[j] = color[i];
                    }
            }
        }

        for (int i = 0; i < n; i++) {
            if (color[i] == -1) {
                result[i] = 0;
            } else {
                int count = 1;
                for (int j = i + 1; j < n; j++) {
                    if (color[i] == color[j]) {
                        count += result[j];
                    }
                }
                result[i] = count;
            }
        }
    }

    return result;
}

